// ========================================================================
// Daten fuer Stellenist-App aufbereiten
// ALLE Perioden beider Schuljahre → je ein API-Call pro Periode
//
// Rechtsgrundlage: § 3 Abs. 1 FESchVO
// Jede Periode hat eigene Deputatswerte. Unser Sync-Endpoint
// mapped DateFrom/DateTo auf Monate und speichert pro Monat.
// Aenderungen zwischen Perioden werden automatisch erkannt.
// ========================================================================

const CONFIG = {
  apiUrl: 'http://192.168.178.43:3001/api/deputate/sync',
  apiKey: 'd4e5f6a7b8c9d0e1f2a3b4c5d6e7f8a9b0c1d2e3',
  maxLehrerProCall: 500,
};

try {
  const inputItems = $input.all();

  if (!inputItems || inputItems.length === 0) {
    return [{ json: { error: 'Keine Daten vom MSSQL-Query erhalten.', skip: true } }];
  }

  // Nach Periode gruppieren (SCHOOLYEAR_ID + TERM_ID)
  const periodenMap = new Map();

  for (const item of inputItems) {
    const d = item.json;
    if (!d.TEACHER_ID || !d.Name || !d.Vollname) continue;

    const key = `${d.SCHOOLYEAR_ID}_${d.TERM_ID}`;

    if (!periodenMap.has(key)) {
      periodenMap.set(key, {
        schuljahrId: d.SCHOOLYEAR_ID,
        termId: d.TERM_ID,
        schuljahrText: d.Schuljahr_Text,
        termName: d.Term_Name,
        dateFrom: d.DateFrom_Formatted,
        dateTo: d.DateTo_Formatted,
        lehrer: [],
      });
    }

    periodenMap.get(key).lehrer.push({
      teacher_id: parseInt(d.TEACHER_ID, 10),
      name: String(d.Name).substring(0, 50),
      vollname: String(d.Vollname).substring(0, 200),
      personalnummer: d.Personalnummer ? String(d.Personalnummer).substring(0, 20).trim() : null,
      stammschule: String(d.Stammschule ?? '').substring(0, 10),
      deputat: Math.round((parseFloat(d.Deputat) || 0) * 1000) / 1000,
      deputat_ges: Math.round((parseFloat(d.Deputat_GES) || 0) * 1000) / 1000,
      deputat_gym: Math.round((parseFloat(d.Deputat_GYM) || 0) * 1000) / 1000,
      deputat_bk: Math.round((parseFloat(d.Deputat_BK) || 0) * 1000) / 1000,
    });
  }

  if (periodenMap.size === 0) {
    return [{ json: { error: 'Keine gueltigen Perioden nach Gruppierung.', skip: true } }];
  }

  // Pro Periode einen Output-Item erzeugen (n8n Loop-Node verarbeitet diese)
  const outputs = [];
  for (const [key, periode] of periodenMap) {
    outputs.push({
      json: {
        api_key: CONFIG.apiKey,
        sync_datum: new Date().toISOString().split('T')[0],
        schuljahr_text: periode.schuljahrText,
        term_id: periode.termId ? parseInt(periode.termId, 10) : undefined,
        date_from: periode.dateFrom,
        date_to: periode.dateTo,
        lehrer: periode.lehrer.slice(0, CONFIG.maxLehrerProCall),
        _perioden_info: {
          key: key,
          term_name: periode.termName,
          anzahl_lehrer: periode.lehrer.length,
        },
      },
    });
  }

  // Sortieren: aelteste Periode zuerst (chronologisch)
  outputs.sort((a, b) => {
    const aKey = a.json._perioden_info.key;
    const bKey = b.json._perioden_info.key;
    return aKey.localeCompare(bKey);
  });

  return outputs;

} catch (error) {
  return [{ json: { error: `Transformation fehlgeschlagen: ${error.message}`, skip: true } }];
}
